fields.content_patch:
{
  // -----------------------------------------------
  // Flashcards demo profile
  // Uses a custom OpenAI API key for flashcard generation
  // -----------------------------------------------
  "processor_config": {
    "LLMProcessor": {
      "options": {
        // Replace with your own OpenAI API key
        "API_KEY": "sk-proj-your-openai-api-key-here",
      },
    },
  },
}

{
  // -----------------------------------------------
  // Box chat with custom summary prompt
  // Overrides the default summary prompt with a more explicit one
  // and provides a dedicated API key
  // -----------------------------------------------
  "processor_config": {
    "LLMProcessor": {
      // Custom prompt asking specifically for a summary
      "prompt": "You are a helpful educational assistant. Summarize the following course content in a clear, concise way. Use bullet points for key concepts and keep the summary under 300 words.",
      "options": {
        // Replace with your own OpenAI API key
        "API_KEY": "sk-proj-your-openai-api-key-here",
      },
    },
  },
  "actuator_config": {
    "UIComponents": {
      "request": {
        "config": {
          "buttonText": "Summarize this unit",
          "customMessage": "Get a concise summary of this content",
        },
      },
      "response": {
        "config": {
          "customMessage": "Here is your summary",
        },
      },
    },
  },
}

{
  // -----------------------------------------------
  // Chat with functions demo
  // Enables function calling (tools) for richer interactions
  // Custom UI component texts and dedicated API key
  // -----------------------------------------------
  "processor_config": {
    "LLMProcessor": {
      "options": {
        // Replace with your own OpenAI API key
        "API_KEY": "sk-proj-your-openai-api-key-here",
      },
    },
  },
  "actuator_config": {
    "UIComponents": {
      "request": {
        "config": {
          // Customized button and message for the functions chat
          "buttonText": "Ask AI (with tools)",
          "customMessage": "Chat with an AI that can look up course content and more",
        },
      },
      "response": {
        "config": {
          "customMessage": "AI assistant (function calling enabled)",
        },
      },
    },
  },
}

{
  // -----------------------------------------------
  // Streaming chat demo
  // Threaded conversation with streaming responses
  // Custom prompt, UI texts, and API key override
  // -----------------------------------------------
  "processor_config": {
    "LLMProcessor": {
      // Custom system-level prompt for the streaming chat
      "prompt": "You are a knowledgeable teaching assistant for this online course. Answer questions clearly and concisely. When referencing course material, be specific about which section you are referring to. Always encourage the student to explore the topic further.",
      "options": {
        // Replace with your own OpenAI API key
        "API_KEY": "sk-proj-your-openai-api-key-here",
      },
    },
  },
  "actuator_config": {
    "UIComponents": {
      "request": {
        "config": {
          // Custom button and welcome text
          "buttonText": "Chat with AI tutor",
          "customMessage": "Start a conversation with your AI teaching assistant",
        },
      },
      "response": {
        "config": {
          "customMessage": "AI Tutor is typing...",
        },
      },
    },
  },
}

{
  // -----------------------------------------------
  // Educator assistant in Studio
  // Helps course authors generate quiz questions
  // Custom UI texts and dedicated API key, no location restriction
  // -----------------------------------------------
  "processor_config": {
    "EducatorAssistantProcessor": {
      "options": {
        // Replace with your own OpenAI API key
        "API_KEY": "sk-proj-your-openai-api-key-here",
      },
    },
  },
  "actuator_config": {
    "UIComponents": {
      "request": {
        "config": {
          // Customized educator-facing text
          "titleText": "Quiz Generator",
          "buttonText": "Generate Questions",
          "customMessage": "Use AI to create multiple-choice questions from this unit content",
        },
      },
      "response": {
        "config": {
          "titleText": "Quiz Generator",
          "customMessage": "Questions generated successfully",
          "hyperlinkText": "Go to library >",
        },
      },
    },
  },
}

{
  // -----------------------------------------------
  // Mocked streaming response
  // For UI/integration testing without a live LLM
  // The API key is included for fixture consistency
  // but is not used by the mock orchestrator
  // -----------------------------------------------
  "processor_config": {
    "LLMProcessor": {
      "options": {
        // Not actually used — mock orchestrator skips the LLM call
        // Included here to demonstrate the content_patch pattern
        "API_KEY": "sk-proj-your-openai-api-key-here",
      },
    },
  },
  "actuator_config": {
    "UIComponents": {
      "request": {
        "config": {
          "buttonText": "Test streaming",
          "customMessage": "Simulated streaming response (no LLM)",
        },
      },
      "response": {
        "config": {
          "customMessage": "Mock streaming in progress...",
        },
      },
    },
  },
}
